import React, { useCallback, useEffect, useRef } from 'react'
import { useEvent } from '@fs/zion-frontend-friends'
import { useFilterSelect } from '@fs/zion-ui-select'
import { useZionFormContext, useController, useFormState } from '@fs/zion-form'
import { PlaceSelect } from '@fs/zion-standards'

const defaultHandleSelection = (suggestion, input) => suggestion?.primaryText ?? input

export default function FormPlaceSelect({ handleSelection = defaultHandleSelection, name, onBlur, ...props }) {
  const { control } = useZionFormContext()
  const { field: input, fieldState } = useController({ name, control })

  let initialState
  if (typeof input.value === 'string') {
    initialState = { userInput: input.value }
  } else if (typeof input.value === 'object' && input.value !== null && 'primaryText' in input.value) {
    initialState = { selectedItem: input.value }
  } else {
    initialState = input.value
  }

  const config = useFilterSelect({ initialState, formatSelection: handleSelection })

  const { userInput, selectedItem, set } = config
  const handleChange = useEvent(input.onChange)

  const previousValueRef = useRef({
    userInput: '',
    selectedItem: null,
  })

  useEffect(() => {
    if (
      userInput === previousValueRef.current?.userInput &&
      selectedItem?.primaryText === previousValueRef.current?.selectedItem?.primaryText
    ) {
      return
    }

    previousValueRef.current = { userInput, selectedItem }
    handleChange({
      userInput,
      selectedItem,
      fieldValue: handleSelection(selectedItem, userInput),
    })
  }, [userInput, selectedItem, handleChange, handleSelection])

  const { isDirty } = fieldState
  const wasDirty = useRef(isDirty)
  const previousInputValue = useRef(input.value)

  useEffect(() => {
    if (!isDirty && wasDirty.current) {
      set(input.value)
    } else if (input.value !== previousInputValue.current) {
      let value = input.value
      if (typeof value === 'string') {
        value = { userInput: value }
      } else if (value?.primaryText) {
        value = { selectedItem: value }
      }
      set(value)
    }

    wasDirty.current = isDirty
    previousInputValue.current = input.value
  }, [isDirty, input.value, set])

  const newOnBlur = useCallback(
    (evt) => {
      input.onBlur()
      onBlur?.(evt)
    },
    [input, onBlur]
  )

  const { errors, touchedFields, isSubmitted } = useFormState({ control, name })
  const fieldError = name.split('.').reduce((obj, key) => obj?.[key], errors)
  const errorMsg = fieldError?.primaryText?.message ?? fieldError?.message
  const showValidation = isSubmitted || name.split('.').reduce((obj, key) => obj?.[key], touchedFields)
  const errorMessage = showValidation ? errorMsg : undefined

  return (
    <PlaceSelect
      {...props}
      onBlur={newOnBlur}
      name={`${input.name}.fieldValue`}
      config={config}
      errorMessage={errorMessage}
    />
  )
}
