import React, { forwardRef, useMemo } from 'react'
import type { ComponentProps } from 'react'
import { FilterSelect } from '@fs/zion-ui-select'
import type { OptionGetter, SelectConfig, Option } from '@fs/zion-ui-select'
import { ThingMapPin } from '@fs/zion-icon'
import { i18n } from '@fs/zion-locale'
import { useEvent } from '@fs/zion-frontend-friends'
import { getPlaceSuggestions } from './PlaceSuggestNEXT'
import { getPlaceLabel } from '../standard-suggest/eventTypes'
import type { EventType } from '../standard-suggest/eventTypes'

/**
 * Filter options for place suggestions
 */
export type PlaceFilterOptions = {
  /** Array of place type names or IDs to require (e.g., ['City', 'State'] or [123, 456]) */
  reqTypes?: (string | number)[]
  /** Array of place type names or IDs to filter out */
  filterTypes?: (string | number)[]
  /** Array of place type group IDs to require */
  reqTypeGroups?: (string | number)[]
  /** Array of place type group IDs to filter out */
  filterTypeGroups?: (string | number)[]
  /** Place hint - comma-delimited list of Place Rep IDs or semi-colon-delimited list of names */
  placeHint?: string | number[]
  /** Level for place hint filtering - affects how impactful the hint is in results */
  placeHintLevel?: 'STRICT' | 'STRONG' | 'NORMAL' | 'WEAK'
  /** Year range string for temporal filtering (e.g., '1900-1950' or '1987,2000') */
  reqYears?: string
  /** Array of direct parent place IDs to require */
  reqDirParents?: number[]
}

/**
 * Props for PlaceSelect component
 */
export type PlaceSelectProps = {
  /** Event type for automatic label generation (e.g., 'birth', 'death', 'marriage') */
  eventType?: EventType
  /** Filter options for place suggestions */
  placeFilterOptions?: PlaceFilterOptions
  /** Show representative IDs in place suggestions */
  showRepIds?: boolean
  /** Use exact matching for place search */
  isExact?: boolean
  /** Hide unsearchable places from results */
  hideUnsearchable?: boolean
  /** INTERNAL USE ONLY. Bypasses cache for fresh suggestions. Setting this to true requires explicit permission from the standards team. */
  noCache?: boolean
  /** Custom label text. Pass null to hide label, string to set custom label, undefined to use eventType label or default "Place" */
  label?: string | null
  /** Override default place suggestions with custom function */
  getOptions?: OptionGetter
  /** SelectConfig from useFilterSelect hook for controlled usage */
  config?: SelectConfig
} & Omit<ComponentProps<typeof FilterSelect>, 'getOptions' | 'config' | 'label' | 'Icon'>

/**
 * PlaceSelect - A dropdown button for selecting standardized places with filtering.
 *
 * Built on top of FilterSelect from @fs/zion-ui-select, this component provides place-specific
 * functionality including automatic label generation, place filtering, and async place suggestion fetching.
 *
 * @example
 * ```tsx
 * // Basic usage
 * <PlaceSelect placeholder="Search for a place..." />
 *
 * // With event type for automatic labeling
 * <PlaceSelect eventType="birth" placeholder="Search for birth place..." />
 *
 * // With filters
 * <PlaceSelect
 *   eventType="marriage"
 *   placeFilterOptions={{ reqTypes: ['City', 'Town'] }}
 * />
 * ```
 */
export const PlaceSelect = forwardRef<HTMLButtonElement, PlaceSelectProps>(
  (
    {
      eventType,
      placeFilterOptions,
      showRepIds,
      isExact,
      hideUnsearchable,
      noCache,
      label,
      config,
      getOptions: getOptionsProp,
      ...rest
    },
    ref
  ) => {
    // Create default adapter function to fetch place suggestions
    // Using useEvent to create a stable callback reference that always accesses latest values
    const defaultGetOptions = useEvent(async (searchTerm: string): Promise<Option[]> => {
      const options: {
        placeFilterOptions?: PlaceFilterOptions
        showRepIds?: boolean
        isExact?: boolean
        hideUnsearchable?: boolean
        noCache?: boolean
      } = {}

      if (placeFilterOptions !== undefined) options.placeFilterOptions = placeFilterOptions
      if (showRepIds !== undefined) options.showRepIds = showRepIds
      if (isExact !== undefined) options.isExact = isExact
      if (hideUnsearchable !== undefined) options.hideUnsearchable = hideUnsearchable
      if (noCache !== undefined) options.noCache = noCache

      const suggestions = await getPlaceSuggestions(searchTerm, options)

      // Include the currently selected item at the top of the list if it exists
      const selectedItem = config?.selectedItem
      if (selectedItem?.key) {
        // Check if selectedItem is already in suggestions (deduplicate by key)
        const isAlreadyInList = suggestions.some((s) => s.key === selectedItem.key)
        if (!isAlreadyInList) {
          return [selectedItem, ...suggestions]
        }
      }

      return suggestions
    })

    // Use provided getOptions or fall back to default
    const resolvedGetOptions = getOptionsProp || defaultGetOptions

    // Determine label based on props (with translated default)
    const resolvedLabel = useMemo(() => {
      if (label === null) return null
      if (typeof label === 'string') return label
      // Use getPlaceLabel which handles eventType and provides translated "Place" default
      return getPlaceLabel(eventType)
    }, [label, eventType])

    // Provide default placeholder if not in rest props
    const defaultPlaceholder = i18n.t('place-suggest.select-placeholder', 'Select a standardized place...')
    const restWithDefaults = {
      placeholder: defaultPlaceholder,
      ...rest, // rest can override the default
    }

    // Show map pin icon if the selected item is a standard place
    const Icon = (config?.selectedItem as Option & { isStandard?: boolean })?.isStandard ? ThingMapPin : undefined

    return (
      <FilterSelect
        Icon={Icon}
        ref={ref}
        label={resolvedLabel}
        getOptions={resolvedGetOptions}
        config={config}
        {...restWithDefaults}
      />
    )
  }
)

PlaceSelect.displayName = 'PlaceSelect'
