import React, { Suspense, useRef, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import * as Yup from 'yup'
import { i18n } from '@fs/zion-locale'
import {
  LabelTooltip,
  DialogOverlayActions,
  DialogOverlay,
  DialogOverlayFooter,
  colors,
  Button,
  Paragraph,
} from '@fs/zion-ui'
import ZionForm, { useZionForm, FormTextField } from '@fs/zion-form'
import { yupResolver } from '@hookform/resolvers/yup'
import { NoticeLoading } from '@fs/zion-icon'
import { usePlaceTypeSuggest } from '@fs/zion-standards'
import FormPlaceSelect from './FormPlaceSelect'
import HelpButton from '../HelpButton/HelpButton'

function getValidationSchema({ excludedParentPlaceTypes, getParentPlaceValidation, getLanguageValidation }) {
  return Yup.object().shape({
    placeName: Yup.string()
      .required(i18n.t('provisional-place.place-name-required.warning', 'Place name is required.'))
      .matches(
        /^(?!\s+$).*/,
        i18n.t('provisional-place.input-blank.warning', 'Input text cannot only contain blank spaces.')
      )
      .test(
        'placeNameTest',
        i18n.t(
          'provisional-place.303-invalid-characters-in-name.warning',
          'The name contains an invalid character. Display names can only contain letters.'
        ),
        (value) => {
          if (!value) {
            return true
          }
          return !/[!"#$%&()*+,./:;<=>?@[\]^_{|}~]/.exec(value)
        }
      ),
    parentPlace: getParentPlaceValidation({ excludedParentPlaceTypes }),
    placeLang: getLanguageValidation({ path: 'placeLang' }),
  })
}

function getParentPlaceLabel(suggestedParentPlaceTypes) {
  if (suggestedParentPlaceTypes?.length < 2) {
    return i18n.t('provisional-place.parent-place.label', 'Parent Place')
  }
  const parentPlace1 = suggestedParentPlaceTypes[0].primaryText
  const parentPlace2 = suggestedParentPlaceTypes[1].primaryText
  return i18n.t('provisional-place.parent1-parent2.label', '{parentPlace1} or {parentPlace2}', {
    parentPlace1,
    parentPlace2,
  })
}

function getParentPlacePlaceholderText(suggestedParentPlaceTypes) {
  if (suggestedParentPlaceTypes?.length < 2) {
    return i18n.t('provisional-place.enter-name.place-holder', 'Enter a name')
  }
  const parentPlace1 = suggestedParentPlaceTypes[0].primaryText
  const parentPlace2 = suggestedParentPlaceTypes[1].primaryText
  return i18n.t('provisional-place.enter-parent1-parent2.label', 'Enter the {parentPlace1} or {parentPlace2}', {
    parentPlace1,
    parentPlace2,
  })
}

const SuggestedParentPlaceTypeIds = {
  20: [186, 201, 391, 376, 378, 'county'], // Cemetery - City, Municipality, Village, Town, Township, County
  186: [209, 221, 323], // City - County, District, Province
  38: [391, 312, 221], // Farm - Village, Parish, District
  266: [209, 221, 201], // Hamlet - County, District, Municipality
  142: [186, 201, 391, 376], // Hospital - City, Municipality, Village, Town
  56: [323, 362, 209, 221], // Island - Province, State, County, District
  201: [221, 323, 209], // Municipality - District, Province, County
  308: [186], // Neighborhood - City
  23: [186, 201, 391, 376, 378, 209], // Place of Worship - City, Municipality, Village, Town, Township, County
  115: [186, 201, 391, 376, 378, 209], // School - City, Municipality, Village, Town, Township, County
  376: [209, 221, 323], // Town - County, District, Province
  378: [209, 221, 323], // Township - County, District, Province
  391: [209, 221, 201], // Village - County, District, Municipality
}

function getSuggestedParentPlaceTypes({ placeType, placeTypes = [] }) {
  const suggestedParentPlaceTypeIds = SuggestedParentPlaceTypeIds[placeType?.id] || []
  return suggestedParentPlaceTypeIds
    .map((id) => {
      return placeTypes.find((type) => type.id === id)
    })
    .filter(Boolean)
}

export default function NarrowSearchFormShared({
  title,
  subtitle,
  overlay,
  placeType,
  narrowSearchFormValues = {},
  noWarning = false,
  onBack,
  onNext,
  onChange,
  FormLanguageComponent,
  getLanguageValidation,
  useExcludedParentPlaceTypes,
  getParentPlaceValidation,
}) {
  const [t] = useTranslation()
  const placeNameRef = useRef()
  const { placeName = '', parentPlace = null, placeLang = null } = narrowSearchFormValues
  const { excludedParentPlaceTypes } = useExcludedParentPlaceTypes()
  const { validPlaceTypes } = usePlaceTypeSuggest()
  const validationSchema = getValidationSchema({
    excludedParentPlaceTypes,
    getParentPlaceValidation,
    getLanguageValidation,
  })
  const initialValues = { placeName, parentPlace, placeLang }
  const suggestedParentPlaceTypes = getSuggestedParentPlaceTypes({ placeType, placeTypes: validPlaceTypes })
  const parentPlaceLabel = getParentPlaceLabel(suggestedParentPlaceTypes)
  const parentPlacePlaceholder = getParentPlacePlaceholderText(suggestedParentPlaceTypes)

  const methods = useZionForm({
    mode: 'all',
    defaultValues: initialValues,
    resolver: yupResolver(validationSchema),
  })
  const {
    reset,
    handleSubmit,
    getValues,
    setValue,
    formState: { isValid },
  } = methods
  const { isOpen, transitioning } = overlay

  React.useEffect(() => {
    if (!isOpen && !transitioning) {
      reset()
    }
  }, [reset, isOpen, transitioning])

  useEffect(() => {
    placeNameRef?.current?.focus()
  }, [])

  return (
    <DialogOverlay
      as={ZionForm}
      methods={methods}
      onSubmit={(values, actions) => {
        onNext({ values, actions })
      }}
      title={title}
      subtitle={subtitle}
      {...overlay}
      closeOnClickAway={false}
    >
      <Suspense fallback={<NoticeLoading />}>
        {!noWarning && (
          <Paragraph>
            {t(
              'provisional-place.narrow-search.warning',
              'FamilySearch will look for possible duplicates before submitting a new place to the standards database.'
            )}
          </Paragraph>
        )}
        <FormTextField
          name="placeName"
          label={t('provisional-place.place-name.label', 'Place Name')}
          placeholder={t('provisional-place.enter-name.place-holder', 'Enter a name')}
          autoComplete="off"
          ref={placeNameRef}
        />
        <FormPlaceSelect
          name="parentPlace"
          label={parentPlaceLabel}
          placeholder={parentPlacePlaceholder}
          helpMessage={
            <LabelTooltip
              label={t(
                'provisional-place.parent-place.tooltip',
                'A parent place is the next largest geographical area that the town of city belongs to. For example, a township might be the parent place to a small village. A county or even state might be the parent place to a large city.'
              )}
              target={
                <span style={{ fontSize: 12, fontStyle: 'italic', textTransform: 'none', color: colors.blue70 }}>
                  {t('provisional-place.what-is-parent-place.label', 'What is a parent place?')}
                </span>
              }
            />
          }
        />
        <FormLanguageComponent
          name="placeLang"
          label={t('provisional-place.language-of-place.label', 'Language of Place Name')}
          handleInput
          onInputTextChange={(txt) => {
            if (!txt) {
              setValue('placeLang', null)
            }
          }}
          placeholder={t('provisional-place.enter-language.place-holder', 'Enter a language')}
        />
        <DialogOverlayFooter>
          <DialogOverlayActions>
            <HelpButton />
            <Button
              emphasis="medium"
              onClick={() => {
                reset()
                onChange(getValues())
                onBack()
              }}
            >
              {t('common-ui:back.action', 'Back')}
            </Button>
            <Button
              type="submit"
              emphasis="high"
              disabled={!getValues().placeName || !getValues().placeLang || !getValues().parentPlace || !isValid}
              onClick={() => {
                onChange(getValues())
                handleSubmit()
              }}
            >
              {t('common-ui:next.action', 'Next')}
            </Button>
          </DialogOverlayActions>
        </DialogOverlayFooter>
      </Suspense>
    </DialogOverlay>
  )
}
