export default function mapPublishedTypesToSuggestions(types, suffix) {
  if (!Array.isArray(types)) {
    return types
  }

  return types
    .filter((type) => type.published)
    .map((type) => ({
      primaryText: type.localizedName[0].name,
      secondaryText: type.localizedName[0].desc,
      key: `${type.id}-${suffix}`,
      id: type.id,
    }))
}
