import axios from '@fs/zion-axios'
import React, { useEffect, useState } from 'react'
import zionDebug from '@fs/zion-debug'
import { i18n } from '@fs/zion-locale'
import * as Yup from 'yup'
import { LabelTooltip } from '@fs/zion-ui'
import mapPublishedTypesToSuggestions from '../lib/mapPublishedTypesToSuggestions'

const debug = zionDebug('standards:places:useExcludedParentPlaceTypes')

let uniqueId = 0
function getXRequestId() {
  const now = Date.now()
  return `${now}-${++uniqueId}-places-react`
}

function getDefaultHeaders() {
  return {
    'Content-Type': 'application/standards-places-v2+json',
    Accept: 'application/json',
    'X-Request-ID': getXRequestId(),
  }
}

export function fetchExcludedParentPlaceTypeGroup(axiosOptions = {}) {
  debug(`useExcludedParentPlaceTypes.fetchExcludedParentPlaceTypeGroup: {language: ${i18n.language}}`)
  return axios.get(`/service/standards/place/ws/places/type-groups/62?acceptLang=${i18n.language}`, {
    headers: getDefaultHeaders(),
    ...axiosOptions,
  })
}

export async function updatePlaceTypes(setExcludedParentPlaceTypes, axiosOptions) {
  const resp = await fetchExcludedParentPlaceTypeGroup(axiosOptions)
  const placeTypes = mapPublishedTypesToSuggestions(resp.data.placeTypeGroup.placeTypes, 'placeType')
  setExcludedParentPlaceTypes(placeTypes)

  return placeTypes
}

const ParentPlaceToolTip = ({ message }) => {
  const parentPlaceTooltipLabel = i18n.t(
    'provisional-place.parent-place.tooltip',
    'A parent place is the next largest geographical area that the town of city belongs to. For example, a township might be the parent place to a small village. A county or even state might be the parent place to a large city.'
  )
  return (
    <LabelTooltip
      label={parentPlaceTooltipLabel}
      target={<div style={{ fontSize: 12, fontStyle: 'italic', textTransform: 'none' }}>{message}</div>}
    />
  )
}

export function getParentPlaceValidation({ excludedParentPlaceTypes }) {
  return Yup.object()
    .nullable()
    .required(
      <ParentPlaceToolTip
        message={i18n.t('provisional-place.parent-place-required.warning', 'Parent place is required.')}
      />
    )
    .test({
      name: 'parentPlaceTypeTest',
      test(value) {
        if (
          value?.selectedItem?.standard?.placeType &&
          !excludedParentPlaceTypes?.find((type) => {
            return type?.primaryText === value?.selectedItem?.standard?.placeType
          })
        ) {
          return true
        }
        if (!value?.selectedItem?.standard) {
          return this.createError({
            message: (
              <ParentPlaceToolTip
                message={i18n.t(
                  'provisional-place.403-parent-place-invalid.warning',
                  'The parent place is invalid or unknown. Please verify your entries and try again.'
                )}
              />
            ),
            path: 'parentPlace',
          })
        }
        return this.createError({
          message: (
            <LabelTooltip
              label={i18n.t(
                'provisional-place.parent-place-type-not-supported.tooltip',
                'FamilySearch restricts editing and creation of places directly within places of type "{placeType}". Please choose a parent place of a lower level type and try again.',
                { placeType: value?.selectedItem?.standard?.placeType }
              )}
              target={
                <div style={{ fontSize: 12, fontStyle: 'italic', textTransform: 'none' }}>
                  {i18n.t(
                    'provisional-place.parent-place-type-not-supported.warning',
                    'Creating provisional places within a parent place of type "{placeType}" requires additional permission.',
                    { placeType: value?.selectedItem?.standard.placeType }
                  )}
                </div>
              }
            />
          ),
          path: 'parentPlace',
        })
      },
    })
}

const defaultAxiosOptions = { fsUserAgentChainSuffix: 'zion-provisional-place' }

export default function useExcludedParentPlaceTypes(axiosOptions = defaultAxiosOptions) {
  const [excludedParentPlaceTypes, setExcludedParentPlaceTypes] = useState([])

  useEffect(() => {
    updatePlaceTypes(setExcludedParentPlaceTypes, axiosOptions)
  }, []) // eslint-disable-line react-hooks/exhaustive-deps

  return { excludedParentPlaceTypes }
}
